query {
  admin: user(role: "ADMIN") { name }
  member: user(role: "MEMBER") { name }
}

mutation {
  createUser(input: { name: "Alice", email: "a@b.c" }) {
    id
    name
  }
}

mutation {
  updateUser(id: "1", input: { name: "Bob" }) {
    id
    name
  }
}

type User {
  id: ID!
  name: String!
  email: String
  posts: [Post!]!
}

input CreateUserInput {
  name: String!
  email: String!
}
